    public static BillCore deploy(Client client, CryptoKeyPair credential, String _initialAdmin)
            throws ContractException {
        @SuppressWarnings("rawtypes")
        byte[] encodedConstructor = FunctionEncoder.encodeConstructor(Arrays.<Type>asList(new org.fisco.bcos.sdk.v3.codec.datatypes.Address(_initialAdmin)));
        return deploy(BillCore.class, client, credential, getBinary(client.getCryptoSuite()), getABI(), encodedConstructor, null);
    }

